## Code Example
```javascript
function isNewVersion(current, incoming) {
  const toNum = s => (s||'0').split('.').map(n => parseInt(n,10));
  const [a,b,c] = toNum(current);
  const [x,y,z] = toNum(incoming);
  if (x !== a) return x > a;
  if (y !== b) return y > b;
  return (z||0) > (c||0);
}
```

